                        stateDesc,
                        new InternalSingleValueWindowFunction<>(
                                new PassThroughWindowFunction<
                                        String, GlobalWindow, Tuple2<String, Integer>>()),
                        PurgingTrigger.of(CountTrigger.of(windowSize)),
                        0,
                        null /* late data output tag */);

